import{_ as a,o as t,c as e,Q as o}from"./chunks/framework.32dba02b.js";const i="/devops-doc/assets/其他系统在每个版本中记录着各个文件的具体差异.dba45a45.png",s="/devops-doc/assets/Git保存每次更新时的文件快照.613406db.png",f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Tools/VersionManagement/point.md","filePath":"Tools/VersionManagement/point.md","lastUpdated":1697596099000}'),r={name:"Tools/VersionManagement/point.md"},n=o('<h2 id="直接记录快照-而非差异比较" tabindex="-1">直接记录快照，而非差异比较 <a class="header-anchor" href="#直接记录快照-而非差异比较" aria-label="Permalink to &quot;直接记录快照，而非差异比较&quot;">​</a></h2><p>Git 和其他版本控制系统的主要差别在于，Git 只关心文件数据的整体是否发生变化，而大多数其他系统则只关心文件内容的具体差异。这类系统（CVS，Subversion，Perforce，Bazaar 等等）每次记录有哪些文件作了更新，以及都更新了哪些行的什么内容。如图所示：</p><p><img src="'+i+'" alt="其他系统在每个版本中记录着各个文件的具体差异"></p><p>Git 并不保存这些前后变化的差异数据。实际上，Git 更像是把变化的文件作快照后，记录在一个微型的文件系统中。每次提交更新时，它会纵览一遍所有文件的指纹信息并对文件作一快照，然后保存一个指向这次快照的索引。为提高性能，若文件没有变化，Git 不会再次保存，而只对上次保存的快照作一链接。如图所示：</p><p><img src="'+s+'" alt="Git保存每次更新时的文件快照"></p><h2 id="近乎所有操作都是本地执行" tabindex="-1">近乎所有操作都是本地执行 <a class="header-anchor" href="#近乎所有操作都是本地执行" aria-label="Permalink to &quot;近乎所有操作都是本地执行&quot;">​</a></h2><p>在 Git 中的绝大多数操作都只需要访问本地文件和资源，不用连网。但如果用 CVCS 的话，差不多所有操作都需要连接网络。因为 Git 在本地磁盘上就保存着所有当前项目的历史更新，所以处理起来速度飞快。</p><h2 id="时刻保持数据完整性" tabindex="-1">时刻保持数据完整性 <a class="header-anchor" href="#时刻保持数据完整性" aria-label="Permalink to &quot;时刻保持数据完整性&quot;">​</a></h2><p>在保存到 Git 之前，所有数据都要进行内容的校验和（checksum）计算，并将此结果作为数据的唯一标识和索引。换句话说，不可能在你修改了文件或目录之后，Git 一无所知。这项特性作为 Git 的设计哲学，建在整体架构的最底层。所以如果文件在传输时变得不完整，或者磁盘损坏导致文件数据缺失，Git 都能立即察觉。</p><h2 id="多数操作仅添加数据" tabindex="-1">多数操作仅添加数据 <a class="header-anchor" href="#多数操作仅添加数据" aria-label="Permalink to &quot;多数操作仅添加数据&quot;">​</a></h2><p>常用的 Git 操作大多仅仅是把数据添加到数据库。因为任何一种不可逆的操作，比如删除数据，都会使回退或重现历史版本变得困难重重。在别的 VCS 中，若还未提交更新，就有可能丢失或者混淆一些修改的内容，但在 Git 里，一旦提交快照之后就完全不用担心丢失数据，特别是养成定期推送到其他仓库的习惯的话。</p>',11),c=[n];function p(d,l,_,h,m,u){return t(),e("div",null,c)}const b=a(r,[["render",p]]);export{f as __pageData,b as default};
